window.partFormatter=function(n){return"<button class='btn btn-sm btn-outline-dark m-1 usePart' data-id='"+n+"'>استفاده<\/button>"};window.partEvents={"click button.usePart":function(){var n,t;n=$(this);t=$("table[data-toggle=table]").data("useUrl");$.ajax({url:t,type:"POST",cache:!1,data:{id:n.data("id")}}).done(function(n){if(!n.data){toastr.error((_ref1=n.message)!=null?_ref1:resource.exception.editError);return}toastr.success(resource.message.saveSuccess);window.$table.bootstrapTable("refresh",{silent:!0,pageNumber:1})}).fail(function(n){toastr.error(n.status===403?resource.exception.forbidden:resource.exception.serverError)})}};window.partsAdditionalParams=function(){return{Brand:$(".part-list #Brand").val(),Category:$(".part-list #Category").val(),Model:$(".part-list #Model").val(),Availability:$(".part-list #Availability").val()}};window.phoneFormatter=function(n){return"<button class='btn btn-sm btn-outline-dark m-1 usePhone' data-id='"+n+"'>استفاده<\/button>"};window.phoneEvents={"click button.usePhone":function(){var n,t;n=$(this);t=$("table[data-toggle=table]").data("useUrl");$.ajax({url:t,type:"POST",cache:!1,data:{id:n.data("id")}}).done(function(n){if(!n.data){toastr.error((_ref1=n.message)!=null?_ref1:resource.exception.editError);return}toastr.success(resource.message.saveSuccess);window.$table.bootstrapTable("refresh",{silent:!0,pageNumber:1})}).fail(function(n){toastr.error(n.status===403?resource.exception.forbidden:resource.exception.serverError)})}};window.phonesAdditionalParams=function(){return{Brand:$(".phone-list #Brand").val(),Model:$(".phone-list #Model").val(),Availability:$(".phone-list #Availability").val()}};